"use strict";(globalThis.webpackChunkcourse=globalThis.webpackChunkcourse||[]).push([[1527],{8732(e,i,n){n.r(i),n.d(i,{assets:()=>c,contentTitle:()=>a,default:()=>h,frontMatter:()=>r,metadata:()=>t,toc:()=>l});const t=JSON.parse('{"id":"foundations/what-is-sisepuede","title":"What is SISEPUEDE?","description":"SISEPUEDE is an integrated Python/Julia modeling framework for exploring country-level decarbonization pathways under deep uncertainty. Rather than producing a single \\"optimal\\" trajectory, it is built around the idea that the future is genuinely unknown \u2014 so the right question is not what will happen but which policies remain robust across the widest range of futures. This lesson introduces what SISEPUEDE is, where it comes from, and why it was designed the way it was.","source":"@site/docs/01-foundations/01-what-is-sisepuede.md","sourceDirName":"01-foundations","slug":"/foundations/what-is-sisepuede","permalink":"/sisepuede/foundations/what-is-sisepuede","draft":false,"unlisted":false,"editUrl":"https://github.com/sisepuede-framework/sisepuede/tree/main/course/docs/01-foundations/01-what-is-sisepuede.md","tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"what-is-sisepuede","title":"What is SISEPUEDE?","sidebar_position":1},"sidebar":"courseSidebar","previous":{"title":"Welcome","permalink":"/sisepuede/"},"next":{"title":"Architecture Overview","permalink":"/sisepuede/foundations/architecture"}}');var s=n(4848),o=n(8453);const r={id:"what-is-sisepuede",title:"What is SISEPUEDE?",sidebar_position:1},a=void 0,c={},l=[{value:"Learning objectives",id:"learning-objectives",level:2},{value:"The problem SISEPUEDE solves",id:"the-problem-sisepuede-solves",level:2},{value:"Who builds it",id:"who-builds-it",level:2},{value:"What makes it different",id:"what-makes-it-different",level:2},{value:"In the codebase",id:"in-the-codebase",level:2},{value:"Recap",id:"recap",level:2}];function d(e){const i={admonition:"admonition",code:"code",em:"em",h2:"h2",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(i.p,{children:['SISEPUEDE is an integrated Python/Julia modeling framework for exploring country-level decarbonization pathways under deep uncertainty. Rather than producing a single "optimal" trajectory, it is built around the idea that the future is genuinely unknown \u2014 so the right question is not ',(0,s.jsx)(i.em,{children:"what will happen"})," but ",(0,s.jsx)(i.em,{children:"which policies remain robust across the widest range of futures"}),". This lesson introduces what SISEPUEDE is, where it comes from, and why it was designed the way it was."]}),"\n",(0,s.jsx)(i.h2,{id:"learning-objectives",children:"Learning objectives"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsx)(i.li,{children:"Explain what SISEPUEDE stands for and what problem it was designed to solve."}),"\n",(0,s.jsx)(i.li,{children:"Describe the role of Decision Making under Deep Uncertainty (DMDU) in the model's experimental design."}),"\n",(0,s.jsx)(i.li,{children:"Identify the four emission sectors SISEPUEDE models and the cross-cutting socioeconomic driver."}),"\n",(0,s.jsx)(i.li,{children:"Name the institutional partners behind SISEPUEDE and the key publications that describe it."}),"\n",(0,s.jsx)(i.li,{children:"Locate the main entry-point files in the codebase that correspond to the model's architecture."}),"\n"]}),"\n",(0,s.jsx)(i.h2,{id:"the-problem-sisepuede-solves",children:"The problem SISEPUEDE solves"}),"\n",(0,s.jsx)(i.p,{children:'Climate policy analysis faces a fundamental tension: decisions must be made today, but the consequences of those decisions play out over decades in systems whose behavior \u2014 economic growth, technology costs, behavioral change, natural carbon cycles \u2014 cannot be known with precision. Standard scenario analysis sidesteps this by picking a small number of "storylines" and optimizing within each one. The problem is that a policy that looks excellent under one storyline can perform poorly under another. Analysts and decision-makers are left without a principled way to compare robustness across the full uncertainty space.'}),"\n",(0,s.jsxs)(i.p,{children:["SISEPUEDE was built specifically to address this. It applies ",(0,s.jsx)(i.strong,{children:"Decision Making under Deep Uncertainty (DMDU)"})," methods, treating the space of possible futures as a high-dimensional domain to be sampled rather than a fixed set of scenarios. The framework generates thousands of futures using Latin Hypercube Sampling (LHS) \u2014 varying both exogenous uncertainties (economic growth rates, technology diffusion) and lever-effect uncertainties (how effective a policy intervention actually is) \u2014 and then evaluates every combination of policy strategy and future. The result is a picture of ",(0,s.jsx)(i.em,{children:"which strategies work across the widest range of conditions"}),", not just which strategy looks best under the analyst's favorite assumptions."]}),"\n",(0,s.jsxs)(i.p,{children:["The emission calculations themselves follow a ",(0,s.jsx)(i.strong,{children:"bottom-up partial equilibrium"})," approach grounded in the ",(0,s.jsx)(i.strong,{children:"2006 IPCC Guidelines for National Greenhouse Gas Inventories"})," and their ",(0,s.jsx)(i.strong,{children:"2019 Refinement"}),". This means every emission factor, activity driver, and gas-conversion constant traces back to a documented IPCC method. Outputs are reported in MT CO2-equivalent using GWP100 values from IPCC AR6 WG1 Chapter 7, Table 7.SM.7. The country or region is the natural unit of analysis, making SISEPUEDE directly applicable to NDC planning, carbon-neutrality roadmaps, and sectoral mitigation cost estimation."]}),"\n",(0,s.jsx)(i.h2,{id:"who-builds-it",children:"Who builds it"}),"\n",(0,s.jsx)(i.p,{children:"SISEPUEDE is a collaboration across three institutions:"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"RAND Corporation"})," \u2014 principal developer James Syme leads the core framework (Python/Julia), the experimental design machinery, and the ",(0,s.jsx)(i.code,{children:"jcsyme/sisepuede"})," GitHub repository."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Inter-American Development Bank (IDB)"})," \u2014 co-funder and primary application partner, supporting country-level implementations across Latin America and the Caribbean."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Tecnol\xf3gico de Monterrey, EGobiernoyTP / Decision Science Center"})," (Dr. Edmundo Molina's group) \u2014 country implementation, input data pipelines, MAC curve integration, and NDC-to-SISEPUEDE transformation mapping."]}),"\n"]}),"\n",(0,s.jsx)(i.p,{children:"Three publications anchor the framework:"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Kalra et al. (2023)"})," \u2014 the core framework paper describing the SISEPUEDE methodology, the DMDU experimental design, and its application to LAC decarbonization analysis."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:'"Costos y beneficios de lograr la carbono-neutralidad en Am\xe9rica Latina y el Caribe"'})," (BID/RAND, 2023) \u2014 regional policy application using SISEPUEDE to estimate the costs and benefits of carbon neutrality across Latin America and the Caribbean."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Esteves et al. (2024)"})," \u2014 ",(0,s.jsx)(i.em,{children:"Frontiers in Climate"})," article on job creation and decarbonization synergies in LAC, demonstrating SISEPUEDE as a platform for co-benefit analysis."]}),"\n"]}),"\n",(0,s.jsx)(i.h2,{id:"what-makes-it-different",children:"What makes it different"}),"\n",(0,s.jsx)(i.p,{children:"Several design choices distinguish SISEPUEDE from other GHG accounting or integrated assessment tools:"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Four IPCC emission sectors plus a socioeconomic driver."})," SISEPUEDE models Agriculture, Forestry and Land Use (AFOLU); Circular Economy (waste management, wastewater, industrial processes); Energy (stationary combustion, transport, electricity generation, fugitive emissions); and IPPU (industrial processes and product use, including F-gases and cement). A fifth module, Socioeconomic, is not an emission sector but drives demand across all others through GDP, population, and trade variables."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"LHS-based DMDU, not scenario trees."})," The framework maintains two separate LHS tables \u2014 one for exogenous uncertainties (",(0,s.jsx)(i.code,{children:"arr_lhs_x"}),") and one for lever-effect uncertainties (",(0,s.jsx)(i.code,{children:"arr_lhs_l"}),") \u2014 and combines them into a four-design structure (baseline, X-only, L-only, full uncertainty). Every run is indexed by a ",(0,s.jsx)(i.code,{children:"primary_id"})," encoding the ",(0,s.jsx)(i.code,{children:"(design_id, strategy_id, future_id)"})," triplet, enabling exact reproducibility and efficient database queries."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Partial equilibrium at country/region scope."})," SISEPUEDE does not solve a global general equilibrium. It takes exogenous demand trajectories (GDP, population) and computes emissions bottom-up from activity levels and emission factors. This makes it tractable for country teams to calibrate and maintain, while remaining consistent with IPCC accounting conventions."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Composable policy transformers."})," Policy interventions are represented as ",(0,s.jsx)(i.strong,{children:"transformers"})," \u2014 functions that modify a baseline input DataFrame to reflect a specific technology or behavioral change. Transformers are catalogued in an official attribute table and can be combined into ",(0,s.jsx)(i.strong,{children:"strategies"}),'. This separation of "what the policy does to the data" from "how the model computes emissions" keeps the experimental design clean and auditable.']}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:"Python/Julia hybrid for energy optimization."})," The electricity sector dispatches generation through a Julia-based LP (NeMo-Mod), called via a SQLite handshake. All other sectors run in pure Python. This allows the computationally intensive LP to be solved efficiently while keeping the rest of the framework accessible to Python practitioners."]}),"\n"]}),"\n",(0,s.jsx)(i.h2,{id:"in-the-codebase",children:"In the codebase"}),"\n",(0,s.jsxs)(i.admonition,{title:"Key entry points",type:"note",children:[(0,s.jsx)(i.p,{children:"The three files below are the best starting points for reading the SISEPUEDE source code."}),(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:(0,s.jsx)(i.code,{children:"sisepuede/core/model_attributes.py"})})," \u2014 ",(0,s.jsx)(i.code,{children:"ModelAttributes"})," class. This is the schema registry: it reads all attribute CSVs, defines every variable name, and enforces consistency across sectors. Every other class receives a ",(0,s.jsx)(i.code,{children:"ModelAttributes"})," instance at construction time."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:(0,s.jsx)(i.code,{children:"sisepuede/manager/sisepuede_models.py"})})," \u2014 ",(0,s.jsx)(i.code,{children:"SISEPUEDEModels"})," class. This orchestrator runs the six sectoral model phases in dependency order (Socioeconomic \u2192 AFOLU \u2192 CircularEconomy \u2192 EnergyProduction \u2192 EnergyConsumption \u2192 IPPU) and assembles the full output table."]}),"\n",(0,s.jsxs)(i.li,{children:[(0,s.jsx)(i.strong,{children:(0,s.jsx)(i.code,{children:"sisepuede/manager/sisepuede.py"})})," \u2014 ",(0,s.jsx)(i.code,{children:"SISEPUEDEExperimentalManager"})," class. Entry point for full experimental runs: reads the base input database, applies LHS sampling, iterates over ",(0,s.jsx)(i.code,{children:"primary_id"})," values, and writes results to the output database."]}),"\n"]})]}),"\n",(0,s.jsx)(i.h2,{id:"recap",children:"Recap"}),"\n",(0,s.jsxs)(i.ul,{children:["\n",(0,s.jsx)(i.li,{children:"SISEPUEDE is a bottom-up, partial equilibrium GHG modeling framework that applies DMDU methods to evaluate the robustness of decarbonization strategies across thousands of sampled futures."}),"\n",(0,s.jsx)(i.li,{children:"It covers four IPCC emission sectors \u2014 AFOLU, Circular Economy, Energy, and IPPU \u2014 plus a Socioeconomic driver, all grounded in 2006 IPCC Guidelines and the 2019 Refinement."}),"\n",(0,s.jsx)(i.li,{children:"The framework is a joint product of RAND Corporation, the Inter-American Development Bank, and Tecnol\xf3gico de Monterrey, documented in three peer-reviewed or institutional publications (Kalra 2023, BID/RAND 2023, Esteves 2024)."}),"\n"]}),"\n",(0,s.jsx)(i.hr,{}),"\n",(0,s.jsx)(i.p,{children:'<Quiz questions={[\n{q: "What does SISEPUEDE\'s use of Latin Hypercube Sampling primarily enable?", choices: [\n{text: "Faster computation of the NeMo-Mod energy LP"},\n{text: "Exploration of robustness across a wide range of uncertain futures", correct: true, explain: "SISEPUEDE generates thousands of (strategy, future) combinations via LHS to evaluate which policies remain robust under deep uncertainty \u2014 a core DMDU principle."},\n{text: "Automatic calibration of IPCC emission factors"},\n]},\n{q: "Which institutional partner leads the core Python/Julia framework development?", choices: [\n{text: "Inter-American Development Bank (IDB)"},\n{text: "Tecnol\xf3gico de Monterrey"},\n{text: "RAND Corporation", correct: true, explain: "James Syme at RAND Corporation is the principal developer of the core SISEPUEDE framework, maintained in the jcsyme/sisepuede GitHub repository."},\n]},\n{q: "What role does the Socioeconomic module play in SISEPUEDE?", choices: [\n{text: "It calculates emissions from industrial processes and product use"},\n{text: "It drives demand across all emission sectors through GDP, population, and trade variables", correct: true, explain: "The Socioeconomic module is not itself an emission sector \u2014 it computes the demand scalars (GDP, GDP per capita, population) that feed into AFOLU, Energy, CircularEconomy, and IPPU."},\n{text: "It manages the LHS sampling tables for exogenous uncertainties"},\n]},\n]}/>'})]})}function h(e={}){const{wrapper:i}={...(0,o.R)(),...e.components};return i?(0,s.jsx)(i,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8453(e,i,n){n.d(i,{R:()=>r,x:()=>a});var t=n(6540);const s={},o=t.createContext(s);function r(e){const i=t.useContext(o);return t.useMemo(function(){return"function"==typeof e?e(i):{...i,...e}},[i,e])}function a(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),t.createElement(o.Provider,{value:i},e.children)}}}]);